public class Main {

    // Average of three integer scores
    public static double computeAverage(int[] subjectScores) {
        int total = 0;
        for (int s : subjectScores) total += s;
        return (double) total / subjectScores.length;
    }

    // Letter grade based on average
    public static String assignGrade(double avg) {
        if      (avg >= 90) return "A";
        else if (avg >= 75) return "B";
        else if (avg >= 60) return "C";
        else                return "F";
    }

    // Index of the student with the highest average
    public static int findTopIndex(int[][] allScores) {
        int    topIdx = 0;
        double topAvg = computeAverage(allScores[0]);
        for (int i = 1; i < allScores.length; i++) {
            double avg = computeAverage(allScores[i]);
            if (avg > topAvg) { topAvg = avg; topIdx = i; }
        }
        return topIdx;
    }

    public static void main(String[] args) {

        // --- Data ---
        String[] names = {"Rahul", "Priya", "Amit", "Sneha", "Vikram"};
        int[][]  scores = {
            {85, 72, 90},   // Rahul
            {92, 88, 95},   // Priya
            {62, 55, 70},   // Amit
            {78, 83, 91},   // Sneha
            {45, 50, 48}    // Vikram
        };

        // --- Report header ---
        System.out.println("================================================");
        System.out.println("          STUDENT GRADE REPORT");
        System.out.println("================================================");
        System.out.printf("%-10s %4s %4s %4s %7s %5s%n",
                          "Name", "M", "S", "E", "Avg", "Grade");
        System.out.println("------------------------------------------------");

        // --- Per-student rows + class total ---
        double classTotal = 0;
        for (int i = 0; i < names.length; i++) {
            double avg   = computeAverage(scores[i]);
            String grade = assignGrade(avg);
            classTotal  += avg;
            System.out.printf("%-10s %4d %4d %4d %7.1f %5s%n",
                names[i],
                scores[i][0], scores[i][1], scores[i][2],
                avg, grade);
        }

        // --- Summary ---
        double classAvg = classTotal / names.length;
        int    topIdx   = findTopIndex(scores);
        System.out.println("================================================");
        System.out.printf("Class Average : %.1f%n", classAvg);
        System.out.printf("Top Student   : %s (%.1f)%n",
                          names[topIdx],
                          computeAverage(scores[topIdx]));
        System.out.printf("Pass count    : %d/%d%n",
                          countPassing(scores), names.length);
    }

    // Count students with average >= 60
    public static int countPassing(int[][] allScores) {
        int count = 0;
        for (int[] s : allScores)
            if (computeAverage(s) >= 60) count++;
        return count;
    }
}

